<?php
$pageTitle='Fixed Assets';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('fixed_assets');
$pdo=getDB();
$accounts=$pdo->query('SELECT id,account_code,account_name,account_type FROM '.table('accounts').' WHERE active=1 ORDER BY account_code')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_asset'){
      $number=nextScopedDocumentNumber($pdo,'fixed_asset',setting('fixed_asset_prefix','FA'),operationalScope($pdo));
      $cost=max(0,(float)$_POST['purchase_cost']);$salvage=max(0,(float)$_POST['salvage_value']);$life=max(1,(int)$_POST['useful_life_months']);
      $pdo->prepare('INSERT INTO '.table('fixed_assets').' (asset_number,asset_name,category,purchase_date,purchase_cost,salvage_value,useful_life_months,accumulated_depreciation,book_value,asset_account_id,accumulated_depreciation_account_id,depreciation_expense_account_id,status,notes) VALUES (?,?,?,?,?,?,?,0,?,?,?,?, "active", ?)')->execute([$number,trim((string)$_POST['asset_name']),trim((string)$_POST['category']),trim((string)$_POST['purchase_date']),$cost,$salvage,$life,$cost,(int)($_POST['asset_account_id']??0)?:null,(int)($_POST['accumulated_depreciation_account_id']??0)?:null,(int)($_POST['depreciation_expense_account_id']??0)?:null,trim((string)$_POST['notes'])]);
      flash('success','Fixed asset created.');
    }elseif($action==='run_depreciation'){
      $result=runFixedAssetDepreciation($pdo,trim((string)$_POST['period_date']));
      flash('success','Depreciation run created '.$result['created'].' lines totaling '.money($result['amount']).'.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'fixed-assets']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/fixed-assets.php');
}
$assets=$pdo->query('SELECT * FROM '.table('fixed_assets').' ORDER BY created_at DESC LIMIT 250')->fetchAll();
$dep=$pdo->query('SELECT d.*,a.asset_number,a.asset_name FROM '.table('fixed_asset_depreciation').' d LEFT JOIN '.table('fixed_assets').' a ON a.id=d.fixed_asset_id ORDER BY d.period_date DESC,d.id DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Asset Accounting</div><h2 class="h4 mb-1">Fixed Assets</h2><p class="text-secondary mb-0">Maintain asset register, straight-line depreciation, accumulated depreciation, and book value.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/financial-close.php"><?php echo t('Financial Close', 'الإغلاق المالي'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_asset"><h2 class="h5 mb-3">Create Asset</h2><input class="form-control mb-2" name="asset_name" placeholder="Asset name" required><input class="form-control mb-2" name="category" placeholder="Category"><label class="form-label">Purchase Date</label><input class="form-control mb-2" type="date" name="purchase_date" value="<?php echo esc(date('Y-m-d')); ?>"><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="purchase_cost" placeholder="Cost"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="salvage_value" placeholder="Salvage"></div></div><label class="form-label mt-2">Life Months</label><input class="form-control mb-2" type="number" name="useful_life_months" value="<?php echo esc(setting('fixed_asset_default_life_months','36')); ?>"><label class="form-label">Asset Account</label><select class="form-select mb-2" name="asset_account_id"><option value="0">None</option><?php foreach($accounts as $a): ?><option value="<?php echo (int)$a['id']; ?>"><?php echo esc($a['account_code'].' · '.$a['account_name']); ?></option><?php endforeach; ?></select><label class="form-label">Accum. Depreciation Account</label><select class="form-select mb-2" name="accumulated_depreciation_account_id"><option value="0">None</option><?php foreach($accounts as $a): ?><option value="<?php echo (int)$a['id']; ?>"><?php echo esc($a['account_code'].' · '.$a['account_name']); ?></option><?php endforeach; ?></select><label class="form-label">Depreciation Expense Account</label><select class="form-select mb-2" name="depreciation_expense_account_id"><option value="0">None</option><?php foreach($accounts as $a): ?><option value="<?php echo (int)$a['id']; ?>"><?php echo esc($a['account_code'].' · '.$a['account_name']); ?></option><?php endforeach; ?></select><textarea class="form-control mb-3" name="notes" rows="2" placeholder="Notes"></textarea><button class="btn btn-brand w-100">Create Asset</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="run_depreciation"><h2 class="h5 mb-3">Run Depreciation</h2><label class="form-label">Period Date</label><input class="form-control mb-3" type="date" name="period_date" value="<?php echo esc(date('Y-m-t')); ?>"><button class="btn btn-success w-100">Run Monthly Depreciation</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Asset Register</h2><table class="table align-middle"><thead><tr><th>Asset</th><th>Cost</th><th>Accum. Dep.</th><th>Book Value</th><th>Life</th><th>Status</th></tr></thead><tbody><?php foreach($assets as $asset): ?><tr><td><strong><?php echo esc($asset['asset_number']); ?></strong><div class="small text-secondary"><?php echo esc($asset['asset_name'].' · '.$asset['category']); ?></div></td><td><?php echo money($asset['purchase_cost']); ?></td><td><?php echo money($asset['accumulated_depreciation']); ?></td><td><?php echo money($asset['book_value']); ?></td><td><?php echo (int)$asset['useful_life_months']; ?> months</td><td><span class="badge bg-<?php echo esc(statusTone($asset['status'])); ?>"><?php echo esc($asset['status']); ?></span></td></tr><?php endforeach; ?><?php if(!$assets): ?><tr><td colspan="6" class="text-secondary">No assets yet.</td></tr><?php endif; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Depreciation History</h2><table class="table"><thead><tr><th>Period</th><th>Asset</th><th>Depreciation</th><th>Accumulated</th><th>Book Value</th></tr></thead><tbody><?php foreach($dep as $d): ?><tr><td><?php echo esc($d['period_date']); ?></td><td><?php echo esc($d['asset_number'].' · '.$d['asset_name']); ?></td><td><?php echo money($d['depreciation_amount']); ?></td><td><?php echo money($d['accumulated_depreciation']); ?></td><td><?php echo money($d['book_value']); ?></td></tr><?php endforeach; ?><?php if(!$dep): ?><tr><td colspan="5" class="text-secondary">No depreciation history yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>